{
  "sentences": [
    {
      "text": "我要買一個便當和一杯咖啡。",
      "pinyin": "Wǒ yào mǎi yī ge biàndāng hé yī bēi kāfēi.",
      "pinyin_numeric": "wo3 yao4 mai3 yi1 ge4 bian4dang1 he2 yi1 bei1 ka1fei1.",
      "translation_en": "I want to buy a bento box and a cup of coffee.",
      "translation_ko": "도시락 하나와 커피 한 잔을 사고 싶어요."
    },
    {
      "text": "請問，這個塑膠袋多少錢？",
      "pinyin": "Qǐngwèn, zhège sùjiāodài duōshǎo qián?",
      "pinyin_numeric": "qing3wen4, zhe4ge4 su4jiao1dai4 duo1shao3 qian2?",
      "translation_en": "Excuse me, how much is this plastic bag?",
      "translation_ko": "실례합니다, 이 비닐봉지는 얼마인가요?"
    },
    {
      "text": "我需要一個環保袋，不要塑膠袋。",
      "pinyin": "Wǒ xūyào yī ge huánbǎo dài, bù yào sùjiāodài.",
      "pinyin_numeric": "wo3 xu1yao4 yi1 ge4 huan2bao3 dai4, bu4 yao4 su4jiao1dai4.",
      "translation_en": "I need an eco-friendly bag, not a plastic bag.",
      "translation_ko": "에코백 하나가 필요해요, 비닐봉지는 필요 없어요."
    },
    {
      "text": "我要用信用卡付款。",
      "pinyin": "Wǒ yào yòng xìnyòngkǎ fùkuǎn.",
      "pinyin_numeric": "wo3 yao4 yong4 xin4yong4ka3 fu4kuan3.",
      "translation_en": "I want to pay by credit card.",
      "translation_ko": "신용카드로 결제할게요."
    },
    {
      "text": "請幫我掃描這個條碼。",
      "pinyin": "Qǐng bāng wǒ sǎomiáo zhège tiáomǎ.",
      "pinyin_numeric": "qing3 bang1 wo3 sao3miao2 zhe4ge4 tiao2ma3.",
      "translation_en": "Please scan this barcode for me.",
      "translation_ko": "이 바코드를 스캔해 주세요."
    },
    {
      "text": "我要買兩瓶礦泉水，有特價嗎？",
      "pinyin": "Wǒ yào mǎi liǎng píng kuàngquánshuǐ, yǒu tèjià ma?",
      "pinyin_numeric": "wo3 yao4 mai3 liang3 ping2 kuang4quan2shui3, you3 te4jia4 ma0?",
      "translation_en": "I want to buy two bottles of mineral water. Is there a special offer?",
      "translation_ko": "생수 두 병을 사고 싶은데, 특가가 있나요?"
    },
    {
      "text": "這個飯糰買一送一，我要兩個。",
      "pinyin": "Zhège fàntuán mǎi yī sòng yī, wǒ yào liǎng ge.",
      "pinyin_numeric": "zhe4ge4 fan4tuan2 mai3 yi1 song4 yi1, wo3 yao4 liang3 ge4.",
      "translation_en": "This rice ball is buy one get one free; I want two.",
      "translation_ko": "이 주먹밥은 하나 사면 하나 공짜예요. 두 개 주세요."
    },
    {
      "title": "請給我兩張收據。",
      "pinyin": "Qǐng gěi wǒ liǎng zhāng shōujù.",
      "pinyin_numeric": "qing3 gei3 wo3 liang3 zhang1 shou1ju4.",
      "translation_en": "Please give me two receipts.",
      "translation_ko": "영수증 두 장 주세요."
    },
    {
      "text": "我要用載具，不要印明細。",
      "pinyin": "Wǒ yào yòng zàijù, bù yào yìn míngxì.",
      "pinyin_numeric": "wo3 yao4 yong4 zai4ju4, bu4 yao4 yin4 ming2xi4.",
      "translation_en": "I want to use the receipt carrier, don't print the details.",
      "translation_ko": "영수증은 모바일로 받을게요, 상세 내역은 출력하지 마세요."
    },
    {
      "text": "總共是兩百五十塊，我付現金。",
      "pinyin": "Zǒnggòng shì liǎng bǎi wǔ shí kuài, wǒ fù xiànjīn.",
      "pinyin_numeric": "zong3gong4 shi4 liang3 bai3 wu3 shi2 kuai4, wo3 fu4 xian4jin1.",
      "translation_en": "The total is 250 dollars; I'll pay cash.",
      "translation_ko": "총 250원입니다. 현금으로 낼게요."
    }
  ]
}
